import { color } from "framer-motion";
import { useMouseMove, animate, useValue } from "react-ui-animate"

function BubbleCursor() {

    // const mx = useValue(0)
    // const my = useValue(0)

    const x = useValue(0)
    const y = useValue(0)
    // const angle = useValue(0)
    // const xAcc = useValue(0)
    // const yAcc = useValue(0)
    // const iAc = 7 // initial accel
    // var xAccPrev = [iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc]
    // var yAccPrev = [iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc,iAc]
    // var angPrev = [0,0,0,0,0,0]
    // const flip = useValue("100%")
    // const maxAcc = 5
    // const minDist = 30

    // var t = 0
    // const WOBBLE = 50
    // var FLOATATE = .3


    const average = array => array.reduce((a, b) => a + b) / array.length;

    function createBubble (mx, my) {
        const container = document.getElementById("animateDiv")
        const createElement = document.createElement('span')

        var size = Math.random() * 100 + 20;
        createElement.style.width = size + "px";
        createElement.style.height = size + "px";


        var posX = mx;
        var posY = my;
        createElement.style.left = posX +  "px"
        createElement.style.top = posY +  "px"

        container.appendChild(createElement)
        console.log("====== added bubble")
        setTimeout(() => {
            createElement.remove()
        }, 500+Math.random()*6000)
    }

    useMouseMove(({mouseX, mouseY}) => {
        mx.value = mouseX;
        my.value = mouseY;

        t += 1 
        if (t >359) {
            t = 0
            FLOATATE = FLOATATE*-1
        }

        var centerW = document.getElementById("animateDiv").clientWidth;
        var centerH = document.getElementById("animateDiv").clientHeight;
        var deltaX = mx.value.value - x.value.value - centerW/2;
        var deltaY = my.value.value - y.value.value - centerH/2;;

        // console.log(Math.abs(deltaY) < minDist && Math.abs(deltaY) >= 0)
        // if (Math.abs(deltaX) < minDist && Math.abs(deltaX) > 0) {
        //   // console.log(deltaX)
        //   deltaX = 0
        //   // console.log(Math.abs(deltaX)/deltaX * minDist)
        // }
        // if (Math.abs(deltaY) < minDist && Math.abs(deltaY) > 0) {
        //   deltaY = 0
        // }
        // console.log("ok")


        // FOR REALLY CLOSE TO MOUSE, REDUCE MOTION ///////////////
            //REGULAR
        if ((deltaX**2 + deltaY**2)**.5 > 60) {
            var angRaw = Math.atan(deltaY/deltaX) * 180/Math.PI
            angPrev.shift();
            angPrev.push(angRaw);

            angle.value = average(angPrev)

            flip.value = "100%"
            if (deltaX < 0) {
            flip.value = "-100%"
            }
            // console.log("=======NOTclose")
        } 
            //CLOSE
        else {
            // console.log("close")
            angle.value = angle.value.value + FLOATATE


        }


        var xAccRaw = deltaX  + Math.sin(3.3*t/360 * Math.PI) * WOBBLE/2 -WOBBLE/4
        var yAccRaw = deltaY  + Math.sin(.5*t/360 * Math.PI) * WOBBLE -WOBBLE/2

        xAccPrev.shift();
        xAccPrev.push(xAccRaw);

        yAccPrev.shift();
        yAccPrev.push(yAccRaw);

        xAcc.value = (average(xAccPrev) / 500) * maxAcc 
        yAcc.value = (average(yAccPrev) / 500) * maxAcc

        console.log(average(xAccPrev).toFixed(0), " | ",average(yAccPrev).toFixed(0))

        x.value = x.value.value + xAcc.value.value;
        y.value = y.value.value + yAcc.value.value;
        // y.value = my.value.value;
  });

  return (
    <animate.div
    id="animateDiv"
    style={{
        width: "100vw",
        height: "100vh",
        backgroundColor: "red",
        position: "fixed",
        top: 0,
        left: 0,
    }}
  >
  </animate.div>


  )
}

export default BubbleCursor;
